The developer expects `ptr->greet()` to call `Dog::greet`, but it always prints "Animal greet". What is the problem?

```cpp
#include <iostream>

class Animal {
public:
    void greet() { std::cout << "Animal greet\n"; }
};

class Dog : public Animal {
public:
    void greet() { std::cout << "Dog greet\n"; }
};

int main() {
    Dog d;
    Animal* ptr = &d;
    ptr->greet();
}
```

